"""HTML parsing utilities using BeautifulSoup"""

import re
from bs4 import BeautifulSoup


def extract_nonce(html):
    """Extract nonce value from HTML form.

    Args:
        html: HTML content string

    Returns:
        Nonce string if found, None otherwise
    """
    soup = BeautifulSoup(html, 'html.parser')
    nonce_input = soup.find('input', {'name': 'nonce'})
    if nonce_input:
        return nonce_input.get('value')
    return None


def extract_input_value(html, name):
    """Extract value from an input field.

    Args:
        html: HTML content string
        name: Input field name

    Returns:
        Field value if found, None otherwise
    """
    soup = BeautifulSoup(html, 'html.parser')
    input_field = soup.find('input', {'name': name})
    if input_field:
        return input_field.get('value', '')
    return None


def extract_select_value(html, name):
    """Extract selected value from a select dropdown.

    Args:
        html: HTML content string
        name: Select field name

    Returns:
        Selected value if found, None otherwise
    """
    soup = BeautifulSoup(html, 'html.parser')
    select = soup.find('select', {'name': name})
    if not select:
        return None

    # Find selected option
    selected = select.find('option', {'selected': True})
    if selected:
        return selected.get('value', '')

    # If no selected option, return first option value as default
    first_option = select.find('option')
    if first_option:
        return first_option.get('value', '')

    return None


def extract_radio_value(html, name):
    """Extract checked radio button value.

    Args:
        html: HTML content string
        name: Radio button name

    Returns:
        Checked value if found, None otherwise
    """
    soup = BeautifulSoup(html, 'html.parser')
    radios = soup.find_all('input', {'type': 'radio', 'name': name})

    for radio in radios:
        if radio.get('checked') is not None:
            return radio.get('value', '')

    return None


def extract_checkbox_value(html, name):
    """Extract checkbox state.

    Args:
        html: HTML content string
        name: Checkbox field name

    Returns:
        True if checked, False otherwise
    """
    soup = BeautifulSoup(html, 'html.parser')
    checkbox = soup.find('input', {'type': 'checkbox', 'name': name})

    if checkbox:
        return checkbox.get('checked') is not None

    return False


def extract_table_data(html, table_id=None, table_class=None):
    """Extract data from an HTML table.

    Args:
        html: HTML content string
        table_id: Table ID attribute (optional)
        table_class: Table class attribute (optional)

    Returns:
        List of dictionaries, one per row
    """
    soup = BeautifulSoup(html, 'html.parser')

    if table_id:
        table = soup.find('table', {'id': table_id})
    elif table_class:
        table = soup.find('table', {'class': table_class})
    else:
        table = soup.find('table')

    if not table:
        return []

    rows = []
    for tr in table.find_all('tr'):
        cells = []
        for td in tr.find_all(['td', 'th']):
            cells.append(td.get_text(strip=True))
        if cells:
            rows.append(cells)

    return rows


def extract_firmware_version(html):
    """Extract firmware/software version from sysinfo page.

    Args:
        html: HTML content from sysinfo.ha page

    Returns:
        Version string if found, None otherwise
    """
    soup = BeautifulSoup(html, 'html.parser')

    # Look for "Software Version" table row
    ths = soup.find_all('th', scope='row')
    for th in ths:
        if 'Software Version' in th.get_text():
            # Get the next td sibling
            td = th.find_next_sibling('td')
            if td:
                version = td.get_text(strip=True)
                # Validate it looks like a version number
                if re.match(r'^\d+\.\d+\.\d+', version):
                    return version

    return None


def extract_all_forms(html):
    """Extract all forms from HTML with their fields and values.

    Args:
        html: HTML content string

    Returns:
        List of form dictionaries with action, method, and fields
    """
    soup = BeautifulSoup(html, 'html.parser')
    forms = []

    for form in soup.find_all('form'):
        form_data = {
            'action': form.get('action', ''),
            'method': form.get('method', 'post').lower(),
            'fields': {}
        }

        # Extract all input fields
        for input_field in form.find_all('input'):
            name = input_field.get('name')
            if not name:
                continue

            input_type = input_field.get('type', 'text').lower()

            if input_type == 'radio':
                if input_field.get('checked') is not None:
                    form_data['fields'][name] = input_field.get('value', '')
            elif input_type == 'checkbox':
                if input_field.get('checked') is not None:
                    form_data['fields'][name] = input_field.get('value', 'on')
            else:
                form_data['fields'][name] = input_field.get('value', '')

        # Extract all select fields
        for select in form.find_all('select'):
            name = select.get('name')
            if not name:
                continue

            selected = select.find('option', {'selected': True})
            if selected:
                form_data['fields'][name] = selected.get('value', '')
            else:
                first_option = select.find('option')
                if first_option:
                    form_data['fields'][name] = first_option.get('value', '')

        # Extract all textarea fields
        for textarea in form.find_all('textarea'):
            name = textarea.get('name')
            if not name:
                continue
            form_data['fields'][name] = textarea.get_text(strip=True)

        forms.append(form_data)

    return forms


def find_all_links(html):
    """Find all links in HTML.

    Args:
        html: HTML content string

    Returns:
        List of href values
    """
    soup = BeautifulSoup(html, 'html.parser')
    links = []

    for a in soup.find_all('a', href=True):
        href = a['href']
        if href:
            links.append(href)

    return links
